import type { CareerQuestion } from "./pharmacy-tech-questions";

  export const pharmacyTechQuestionsBatch9: CareerQuestion[] = [
    {id:"pt-b9-001",stem:"Pembrolizumab (Keytruda) belongs to which class of cancer therapy?",options:["Hormonal therapy","Antimetabolite","PD-1 immune checkpoint inhibitor","Alkylating agent"],correctIndex:2,rationale:"Pembrolizumab is a humanized monoclonal antibody against PD-1. By blocking the PD-1/PD-L1 interaction, it reactivates the immune system to attack tumor cells. Used for multiple cancers including melanoma, NSCLC, and others.",difficulty:5,category:"Pharmacology",topic:"oncology"},
    {id:"pt-b9-002",stem:"The brand name for bupropion is:",options:["Zoloft","Effexor","Wellbutrin (also marketed as Zyban for smoking cessation)","Prozac"],correctIndex:2,rationale:"Bupropion is marketed as Wellbutrin (depression), Wellbutrin SR/XL (depression), and Zyban (smoking cessation). It is an NDRI with the lowest sexual side effects among antidepressants.",difficulty:5,category:"Pharmacology",topic:"brand/generic names"},
    {id:"pt-b9-003",stem:"Rifampin is a potent inducer of which cytochrome P450 enzyme?",options:["CYP2E1 only","No CYP enzymes","CYP3A4 (and multiple other CYP enzymes and transporters)","CYP1A2 only"],correctIndex:2,rationale:"Rifampin is one of the most potent CYP inducers known, significantly inducing CYP3A4, CYP2C9, CYP2C19, CYP2B6, and P-glycoprotein. It can dramatically reduce levels of many co-administered drugs.",difficulty:5,category:"Pharmacology",topic:"drug interactions"},
    {id:"pt-b9-004",stem:"Sumatriptan (Imitrex) is used for acute treatment of migraines. Its mechanism is:",options:["Calcium channel blocker","NSAID","Selective 5-HT1B/1D receptor agonist causing cranial vasoconstriction","Beta-blocker"],correctIndex:2,rationale:"Sumatriptan activates 5-HT1B/1D receptors on intracranial blood vessels and trigeminal nerve endings, causing vasoconstriction and inhibiting nociceptive neuropeptide release. Contraindicated in cardiovascular disease.",difficulty:5,category:"Pharmacology",topic:"mechanism of action"},
    {id:"pt-b9-005",stem:"Which medication has a specific warning about the risk of progressive multifocal leukoencephalopathy (PML)?",options:["Metformin","Natalizumab (Tysabri)","Omeprazole","Lisinopril"],correctIndex:1,rationale:"Natalizumab carries a black box warning for PML, a rare and often fatal demyelinating disease caused by JC virus. Risk increases with JCV antibody positivity, prior immunosuppressant use, and treatment duration >2 years.",difficulty:5,category:"Medication Safety",topic:"black box warnings"},
    {id:"pt-b9-006",stem:"Testosterone cypionate injection is classified under which DEA schedule?",options:["Schedule II","Schedule IV","Not scheduled","Schedule III"],correctIndex:3,rationale:"Anabolic steroids, including testosterone cypionate, are classified as Schedule III controlled substances due to potential for abuse. They require a prescription and are subject to Schedule III record-keeping requirements.",difficulty:5,category:"Pharmacy Law",topic:"DEA schedules"},
    {id:"pt-b9-007",stem:"The abbreviation 'OU' in an ophthalmic prescription means:",options:["By mouth","Both eyes (oculi uterque)","Left eye only","Right eye only"],correctIndex:1,rationale:"OU = oculi uterque = both eyes. Used in ophthalmic prescriptions. ISMP recommends writing 'both eyes' instead of OU to prevent confusion with other abbreviations.",difficulty:5,category:"Medication Order Processing",topic:"sig codes"},
    {id:"pt-b9-008",stem:"A compounding pharmacy uses a Class II Type B2 biological safety cabinet for hazardous drug preparation because:",options:["It recirculates all air within the cabinet","It is cheaper than other options","It exhausts 100% of contaminated air to the outside and provides both product and personnel protection","No specific BSC type is required for hazardous drugs"],correctIndex:2,rationale:"Class II Type B2 BSCs exhaust 100% of air through HEPA filters to the outside, preventing hazardous drug exposure to the compounder and environment. Type A2 BSCs can also be used with proper ducting per USP <800>.",difficulty:5,category:"Compounding",topic:"hazardous drug equipment"},
    {id:"pt-b9-009",stem:"When compounding an oral liquid from crushed tablets, which vehicle provides the best suspending properties?",options:["Ora-Plus (suspending vehicle) mixed with Ora-Sweet (flavoring vehicle)","Orange juice","Plain water","Carbonated water"],correctIndex:0,rationale:"Ora-Plus is a commercial suspending vehicle that keeps drug particles uniformly distributed. Mixed 1:1 with Ora-Sweet (sweetened flavoring vehicle) or Ora-Sweet SF (sugar-free), it creates palatable suspensions.",difficulty:1,category:"Compounding",topic:"suspension vehicles"},
    {id:"pt-b9-010",stem:"The purpose of an air sampling test (viable and nonviable) in a cleanroom is:",options:["To verify that air quality meets the required ISO classification by measuring particulate counts and microbial contamination","To test water quality","To check drug potency","To measure humidity"],correctIndex:0,rationale:"Air sampling verifies ISO classification. Nonviable sampling counts particles ≥0.5 microns. Viable sampling detects airborne microorganisms using settle plates or active air samplers. Both are required for USP <797> compliance.",difficulty:1,category:"Compounding",topic:"environmental monitoring"},
    {id:"pt-b9-011",stem:"How many mEq of sodium are in 1 liter of 0.9% NaCl (molecular weight of NaCl = 58.5)?",options:["100 mEq","154 mEq","77 mEq","308 mEq"],correctIndex:1,rationale:"0.9% NaCl = 9 g/L. Millimoles: 9000 mg / 58.5 mg/mmol = 153.8 mmol. Since NaCl dissociates 1:1, Na+ = 154 mEq/L and Cl- = 154 mEq/L.",difficulty:1,category:"Pharmacy Calculations",topic:"electrolyte calculations"},
    {id:"pt-b9-012",stem:"A pharmacy's net profit is calculated as:",options:["Gross profit minus all operating expenses (overhead)","Revenue only","Revenue minus drug costs only","Gross profit only"],correctIndex:0,rationale:"Net profit = Gross profit - Operating expenses (rent, utilities, salaries, insurance, depreciation, etc.). It represents the actual profitability of the pharmacy after all costs are deducted.",difficulty:1,category:"Pharmacy Calculations",topic:"business calculations"},
    {id:"pt-b9-013",stem:"Which antifungal medication inhibits fungal cell wall synthesis?",options:["Terbinafine — an allylamine","Caspofungin (Cancidas) — an echinocandin","Amphotericin B — a polyene","Fluconazole — an azole"],correctIndex:1,rationale:"Echinocandins (caspofungin, micafungin, anidulafungin) inhibit beta-1,3-D-glucan synthase, preventing fungal cell wall synthesis. Azoles inhibit ergosterol synthesis. Polyenes bind ergosterol. Allylamines inhibit squalene epoxidase.",difficulty:1,category:"Pharmacology",topic:"mechanism of action"},
    {id:"pt-b9-014",stem:"What is the generic name for Invega Sustenna?",options:["Haloperidol","Aripiprazole","Paliperidone palmitate","Risperidone"],correctIndex:2,rationale:"Invega Sustenna is paliperidone palmitate, a long-acting injectable (LAI) atypical antipsychotic given monthly for schizophrenia. Invega Trinza is the 3-month formulation. Paliperidone is the active metabolite of risperidone.",difficulty:1,category:"Pharmacology",topic:"brand/generic names"},
    {id:"pt-b9-015",stem:"A patient asks about the difference between immediate-release (IR) and extended-release (ER) formulations. The key difference is:",options:["ER is always more expensive","ER is always stronger than IR","IR is only available as a liquid","ER releases the drug slowly over time, providing sustained blood levels and less frequent dosing, while IR releases the drug immediately"],correctIndex:3,rationale:"Extended-release formulations use matrix, membrane, osmotic, or multiparticulate technology to release drug slowly over 8-24 hours. This reduces dosing frequency and peak-trough fluctuations compared to IR formulations.",difficulty:1,category:"Pharmacology",topic:"dosage forms"},
    {id:"pt-b9-016",stem:"Which medication requires a negative pregnancy test before each monthly dispensing?",options:["Metformin","Ibuprofen","Isotretinoin (iPLEDGE REMS program)","Omeprazole"],correctIndex:2,rationale:"Isotretinoin's iPLEDGE REMS requires two negative pregnancy tests before starting (one at qualification, one at initiation) and monthly pregnancy tests during therapy. Category X teratogen.",difficulty:1,category:"Medication Safety",topic:"REMS programs"},
    {id:"pt-b9-017",stem:"The Combat Methamphetamine Epidemic Act limits pseudoephedrine purchases to a maximum of:",options:["3.6 grams per day and 9 grams per 30-day period","100 tablets per month","1 gram per day","No limit"],correctIndex:0,rationale:"CMEA limits: 3.6 g/day retail, 9 g/30-day period (7.5 g/30 days by mail order). Purchases are logged electronically. Buyer must show photo ID. Products kept behind the counter.",difficulty:1,category:"Pharmacy Law",topic:"pseudoephedrine regulations"},
    {id:"pt-b9-018",stem:"What is the role of the National Provider Identifier (NPI) in pharmacy?",options:["A patient's insurance number","A DEA registration number","A drug identification number","A unique 10-digit number assigned to healthcare providers (including pharmacies and pharmacists) for billing and identification purposes"],correctIndex:3,rationale:"The NPI (mandated by HIPAA) is a standard unique identifier for healthcare providers. Type 1 NPI: individual providers. Type 2 NPI: organizations. Required on all insurance claims and transactions.",difficulty:1,category:"Medication Order Processing",topic:"provider identification"},
    {id:"pt-b9-019",stem:"When a prescription drug has a 'Tier 3' designation on an insurance formulary, this typically means:",options:["It is a non-preferred brand with a higher copay than Tier 1 (generic) or Tier 2 (preferred brand)","It is the cheapest option","It requires no copay","It is not covered at all"],correctIndex:0,rationale:"Common formulary tiers: Tier 1 (preferred generics, lowest copay), Tier 2 (preferred brands, moderate copay), Tier 3 (non-preferred brands, higher copay), Tier 4 (specialty drugs, highest copay or coinsurance).",difficulty:1,category:"Medication Order Processing",topic:"formulary tiers"},
    {id:"pt-b9-020",stem:"A medication has a half-life of 6 hours. After 24 hours, what fraction of the original dose remains?",options:["1/2","1/8","1/4","1/16 (6.25%)"],correctIndex:3,rationale:"Number of half-lives: 24 hours / 6 hours = 4 half-lives. Remaining: (1/2)^4 = 1/16 = 6.25% of the original dose.",difficulty:1,category:"Pharmacy Calculations",topic:"half-life calculations"},
    {id:"pt-b9-021",stem:"Which controlled substance has been moved from Schedule III to Schedule II in recent years?",options:["Tramadol","Codeine with acetaminophen","Hydrocodone combination products (effective October 2014)","Alprazolam"],correctIndex:2,rationale:"On October 6, 2014, all hydrocodone combination products were reclassified from Schedule III to Schedule II, making them subject to more restrictive prescribing and dispensing rules (no refills, no phone-in except emergencies).",difficulty:1,category:"Pharmacy Law",topic:"DEA schedule changes"},
    {id:"pt-b9-022",stem:"A community pharmacy's workflow typically follows which sequence?",options:["No standard workflow exists","Count → Enter → Check → Bag","Receive/intake → Data entry → Clinical review → Fill/count → Final check → Bag/sell → Patient counseling","Bag → Count → Enter → Sell"],correctIndex:2,rationale:"The pharmacy workflow ensures accuracy and safety: prescription receipt and intake, data entry (technician), clinical/DUR review (pharmacist), fill/count (technician), final verification (pharmacist), packaging, and patient counseling (pharmacist).",difficulty:1,category:"Medication Order Processing",topic:"pharmacy workflow"},
    {id:"pt-b9-023",stem:"Which antiviral medication is used for post-exposure prophylaxis of influenza?",options:["Acyclovir","Ribavirin","Oseltamivir (Tamiflu) within 48 hours of exposure","Remdesivir"],correctIndex:2,rationale:"Oseltamivir (neuraminidase inhibitor) is FDA-approved for influenza prophylaxis in patients ≥1 year. For PEP, it is taken once daily for 10 days after close contact with an infected person.",difficulty:1,category:"Pharmacology",topic:"antiviral medications"},
    {id:"pt-b9-024",stem:"Benztropine (Cogentin) is used as an adjunctive therapy with antipsychotics to treat:",options:["Psychosis","Insomnia","Depression","Extrapyramidal symptoms (EPS) including dystonia and parkinsonism"],correctIndex:3,rationale:"Benztropine is an anticholinergic/antihistamine used to treat antipsychotic-induced EPS (dystonia, akathisia, parkinsonism, drug-induced tremor). It blocks muscarinic receptors to restore dopamine-acetylcholine balance.",difficulty:2,category:"Pharmacology",topic:"CNS medications"},
    {id:"pt-b9-025",stem:"The generic name for Symbicort is:",options:["Fluticasone/salmeterol","Beclomethasone/albuterol","Budesonide/formoterol","Mometasone/formoterol"],correctIndex:2,rationale:"Symbicort combines budesonide (ICS) with formoterol (LABA) in a metered-dose inhaler for asthma and COPD maintenance. Advair is fluticasone/salmeterol. Dulera is mometasone/formoterol.",difficulty:2,category:"Pharmacology",topic:"brand/generic names"},
    {id:"pt-b9-026",stem:"What auxiliary label should accompany nitroglycerin sublingual tablets?",options:["Take with a full glass of water","Do not swallow—place under the tongue and allow to dissolve","Chew thoroughly before swallowing","Take with food"],correctIndex:1,rationale:"Nitroglycerin SL tablets must be placed under the tongue and allowed to dissolve. Swallowing undergoes extensive first-pass metabolism, dramatically reducing bioavailability. Patient should sit or lie down.",difficulty:2,category:"Medication Safety",topic:"auxiliary labels"},
    {id:"pt-b9-027",stem:"When compounding a troche (lozenge), the most common base used is:",options:["Cocoa butter","Mineral oil","Petroleum jelly","Polyethylene glycol (PEG) base or silica gel base"],correctIndex:3,rationale:"Troches are made with a PEG base (or other mold-able bases like silica gel/acacia) that slowly dissolves in the mouth, releasing medication for local or systemic absorption through the oral mucosa.",difficulty:2,category:"Compounding",topic:"troche compounding"},
    {id:"pt-b9-028",stem:"Phytonadione is the generic name for:",options:["Vitamin B12","Vitamin D","Vitamin C","Vitamin K1"],correctIndex:3,rationale:"Phytonadione (Vitamin K1) is used to reverse warfarin over-anticoagulation and for vitamin K-deficient bleeding. IV administration for serious bleeding; oral for non-urgent INR correction.",difficulty:2,category:"Pharmacology",topic:"antidotes"},
    {id:"pt-b9-029",stem:"Linaclotide (Linzess) is indicated for:",options:["GERD","Irritable bowel syndrome with constipation (IBS-C) and chronic idiopathic constipation (CIC)","Ulcerative colitis","Diarrhea"],correctIndex:1,rationale:"Linaclotide is a guanylate cyclase-C agonist that increases intestinal fluid secretion and transit. It also reduces visceral pain in IBS-C. Must be taken on an empty stomach 30 minutes before the first meal.",difficulty:2,category:"Pharmacology",topic:"GI medications"},
    {id:"pt-b9-030",stem:"The Joint Commission's National Patient Safety Goals for pharmacies include:",options:["Eliminating all generic drugs","Reducing pharmacy hours","Improving the accuracy of patient identification, using at least two identifiers","Using only brand-name medications"],correctIndex:2,rationale:"Joint Commission NPSGs relevant to pharmacy include: accurate patient identification (2 identifiers), improving medication safety (high-alert drugs, LASA, reconciliation), and reducing healthcare-associated infections.",difficulty:2,category:"Medication Safety",topic:"patient safety goals"},
    {id:"pt-b9-031",stem:"A pharmacy technician notices that two different drugs have been placed in the same bin. This is an example of:",options:["An acceptable practice","Proper stock rotation","Normal inventory organization","A mix-up error that could lead to dispensing the wrong medication"],correctIndex:3,rationale:"Storing different medications in the same bin creates a high risk of dispensing errors. Each drug should have a clearly labeled, dedicated storage location. This is a safety concern requiring immediate correction.",difficulty:2,category:"Medication Safety",topic:"storage safety"},
    {id:"pt-b9-032",stem:"What is the maximum number of refills allowed for a non-controlled prescription medication under federal law?",options:["5 refills","No federal maximum—controlled by state law, but typically up to 12 months from the date written","3 refills","11 refills"],correctIndex:1,rationale:"Federal law does not set a maximum number of refills for non-controlled medications. Most states limit prescription validity to 1 year from the date written, allowing refills as authorized by the prescriber within that period.",difficulty:2,category:"Pharmacy Law",topic:"refill limits"},
    {id:"pt-b9-033",stem:"A medication passes through first-pass metabolism. This means:",options:["The drug bypasses the liver entirely","The drug is absorbed faster","The drug is not metabolized at all","After oral absorption, the drug is metabolized by the liver before reaching systemic circulation, reducing bioavailability"],correctIndex:3,rationale:"First-pass (presystemic) metabolism occurs when an orally absorbed drug passes through the liver via the portal circulation before reaching systemic blood. This can significantly reduce the amount of active drug available. IV, SL, transdermal, and rectal routes partially or fully bypass first-pass metabolism.",difficulty:2,category:"Pharmacology",topic:"pharmacokinetics"},
    {id:"pt-b9-034",stem:"Buprenorphine/naloxone (Suboxone) is used for:",options:["Opioid use disorder (OUD) as maintenance treatment and for medically supervised withdrawal","Acute pain management","Blood pressure control","Diabetes management"],correctIndex:0,rationale:"Suboxone combines buprenorphine (partial mu-opioid agonist) with naloxone (to deter IV misuse). Sublingual administration allows buprenorphine absorption while naloxone has poor SL bioavailability.",difficulty:2,category:"Pharmacology",topic:"addiction medicine"},
    {id:"pt-b9-035",stem:"Which medication requires a 14-day washout period before switching to or from an MAOI?",options:["Metformin","Acetaminophen","Most SSRIs (except fluoxetine which requires 5 weeks due to long half-life)","Omeprazole"],correctIndex:2,rationale:"A 14-day washout is required between MAOIs and most serotonergic drugs (SSRIs, SNRIs, TCAs) to prevent serotonin syndrome. Fluoxetine requires a 5-week washout due to its long-acting metabolite norfluoxetine.",difficulty:2,category:"Medication Safety",topic:"drug interactions"},
    {id:"pt-b9-036",stem:"The term 'contraindication' means:",options:["A side effect that is expected","A recommended treatment","A condition or factor that makes a particular treatment inadvisable due to risk of harm","An off-label use"],correctIndex:2,rationale:"An absolute contraindication means the treatment should never be used (e.g., ACE inhibitors in pregnancy). A relative contraindication means the treatment may be used if the benefit outweighs the risk.",difficulty:2,category:"Pharmacology",topic:"terminology"},
    {id:"pt-b9-037",stem:"Sirolimus (Rapamune) is an immunosuppressant that works by:",options:["Inhibiting mTOR (mechanistic target of rapamycin) to block T-cell proliferation","Blocking B-cell activation directly","Inhibiting COX-2","Inhibiting calcineurin"],correctIndex:0,rationale:"Sirolimus (rapamycin) inhibits mTOR, a kinase critical for cell cycle progression. Unlike calcineurin inhibitors (tacrolimus, cyclosporine), it blocks the response to IL-2 rather than IL-2 production.",difficulty:2,category:"Pharmacology",topic:"immunosuppressants"},
    {id:"pt-b9-038",stem:"The generic name for Harvoni is:",options:["Elbasvir/grazoprevir","Glecaprevir/pibrentasvir","Sofosbuvir/velpatasvir","Ledipasvir/sofosbuvir"],correctIndex:3,rationale:"Harvoni is ledipasvir (NS5A inhibitor) combined with sofosbuvir (NS5B polymerase inhibitor). It was a breakthrough treatment for hepatitis C genotype 1 with cure rates exceeding 95%.",difficulty:2,category:"Pharmacology",topic:"brand/generic names"},
    {id:"pt-b9-039",stem:"Which class of oral hypoglycemics increases the risk of bone fractures?",options:["Metformin","Sulfonylureas","Thiazolidinediones (pioglitazone) — especially in postmenopausal women","DPP-4 inhibitors"],correctIndex:2,rationale:"Thiazolidinediones (pioglitazone, rosiglitazone) decrease bone density by shifting mesenchymal stem cell differentiation from osteoblasts to adipocytes. Fracture risk is increased, particularly in women.",difficulty:3,category:"Pharmacology",topic:"side effects"},
    {id:"pt-b9-040",stem:"How should a pharmacy technician handle a prescription that appears to have been altered?",options:["Ignore the alteration and process it","Fill the prescription as presented","Alert the pharmacist immediately; do not fill the prescription until the prescriber verifies the prescription's authenticity","Change it back to what seems correct"],correctIndex:2,rationale:"An altered prescription is a potential forgery or tampering attempt. The technician must notify the pharmacist, who will contact the prescriber to verify. The original prescription should be retained for investigation.",difficulty:3,category:"Medication Safety",topic:"prescription verification"},
    {id:"pt-b9-041",stem:"Dimethyl fumarate (Tecfidera) is used for the treatment of:",options:["Type 2 diabetes","COPD","Hypertension","Relapsing forms of multiple sclerosis"],correctIndex:3,rationale:"Dimethyl fumarate is an oral disease-modifying therapy for relapsing MS. Its mechanism involves Nrf2 pathway activation, providing anti-inflammatory and cytoprotective effects. Common side effects include flushing and GI symptoms.",difficulty:3,category:"Pharmacology",topic:"neurological medications"},
    {id:"pt-b9-042",stem:"What is the proper storage requirement for reconstituted amoxicillin oral suspension?",options:["Freeze after reconstitution","Refrigerate (2-8°C) after reconstitution with a BUD of 14 days","No special storage required","Store at room temperature for 30 days"],correctIndex:1,rationale:"Reconstituted amoxicillin suspension must be refrigerated and has a 14-day BUD. The pharmacist/technician should label it with the 14-day discard date and instruct the patient to shake well before use.",difficulty:3,category:"Inventory Management",topic:"reconstituted drug storage"},
    {id:"pt-b9-043",stem:"A 'specialty pharmacy' typically handles medications that:",options:["Are only generic medications","Are only for children","Are high-cost, require special handling/administration, and treat complex or rare conditions (e.g., biologics, chemotherapy, HIV drugs)","Are simple OTC products"],correctIndex:2,rationale:"Specialty pharmacies dispense complex, high-cost medications requiring special storage, handling, administration, or monitoring. They provide enhanced clinical services, REMS compliance, and typically serve patients with rare or complex diseases.",difficulty:3,category:"Medication Order Processing",topic:"specialty pharmacy"},
    {id:"pt-b9-044",stem:"The 'therapeutic window' of a drug refers to:",options:["The range of drug concentrations in the blood between the minimum effective concentration and the minimum toxic concentration","The dosing frequency","The time it takes for the drug to work","The shelf life of the drug"],correctIndex:0,rationale:"The therapeutic window (therapeutic range) is the concentration range where the drug produces desired effects without unacceptable toxicity. Drugs with narrow therapeutic windows (warfarin, lithium, digoxin) require monitoring.",difficulty:3,category:"Pharmacology",topic:"pharmacokinetics"},
    {id:"pt-b9-045",stem:"When should warfarin therapy be bridged with a parenteral anticoagulant?",options:["Only for elderly patients","At initiation of warfarin therapy, since warfarin takes 3-5 days to achieve therapeutic effect, during which time the patient remains at risk for clotting","Only during surgery","Never"],correctIndex:1,rationale:"Warfarin requires 3-5 days to achieve therapeutic INR. During this period, bridging with LMWH or UFH provides immediate anticoagulation. Once INR is therapeutic (2-3) for 2 consecutive days, the bridge is discontinued.",difficulty:3,category:"Pharmacology",topic:"anticoagulant therapy"},
    {id:"pt-b9-046",stem:"What is the proper disposal method for non-controlled, non-hazardous expired medications in a community pharmacy?",options:["Give to patients","Throw in regular trash","Return to a reverse distributor for proper disposal per DEA and environmental regulations","Flush down the toilet"],correctIndex:2,rationale:"Expired medications should be segregated, documented, and returned to a licensed reverse distributor for proper disposal. Non-hazardous drugs should not be flushed (environmental contamination) unless on the FDA flush list.",difficulty:3,category:"Inventory Management",topic:"drug disposal"},
    {id:"pt-b9-047",stem:"A DEA Form 224 is used for:",options:["Reporting theft","Ordering Schedule II drugs","Requesting drug destruction","Initial registration of a pharmacy to dispense controlled substances"],correctIndex:3,rationale:"DEA Form 224 is the application for initial registration to manufacture, distribute, or dispense controlled substances. Form 224a is for renewal. Pharmacies must renew every 3 years.",difficulty:3,category:"Pharmacy Law",topic:"DEA registration"},
    {id:"pt-b9-048",stem:"The abbreviation 'pc' means:",options:["As needed","By mouth","Before meals","After meals (post cibum)"],correctIndex:3,rationale:"pc = post cibum = after meals. ac = ante cibum = before meals. These Latin abbreviations indicate timing relative to meals for medication administration.",difficulty:3,category:"Medication Order Processing",topic:"sig codes"},
    {id:"pt-b9-049",stem:"A 'prior authorization' is required by insurance when:",options:["The pharmacy is closed","The patient refuses the medication","The insurance plan requires clinical justification from the prescriber before covering a specific medication","The drug is OTC"],correctIndex:2,rationale:"Prior authorization is a utilization management tool requiring the prescriber to demonstrate medical necessity for a non-formulary or restricted medication before the plan will approve coverage. Processing typically takes 24-72 hours.",difficulty:3,category:"Medication Order Processing",topic:"prior authorization"},
    {id:"pt-b9-050",stem:"Which IV solution is isotonic?",options:["Sterile Water for Injection","0.45% NaCl","0.9% NaCl (Normal Saline) and D5W (before metabolism of dextrose)","3% NaCl"],correctIndex:2,rationale:"0.9% NaCl (~308 mOsm/L) is isotonic with plasma. D5W is initially isotonic but becomes hypotonic after dextrose is metabolized, leaving free water. SWFI is hypotonic and should never be given IV directly (hemolysis risk).",difficulty:3,category:"Pharmacology",topic:"IV solutions"},
    {id:"pt-b9-051",stem:"A prescription reads 'Azithromycin 250 mg, Z-pack.' This contains how many tablets and what is the dosing regimen?",options:["10 tablets over 10 days","3 tablets over 3 days","14 tablets over 14 days","6 tablets: 2 on day 1, then 1 tablet daily on days 2-5"],correctIndex:3,rationale:"The Z-pack contains six 250 mg azithromycin tablets. Dosing: 500 mg (2 tabs) on day 1, then 250 mg (1 tab) on days 2-5. Total: 1.5 grams over 5 days.",difficulty:3,category:"Medication Order Processing",topic:"common regimens"},
    {id:"pt-b9-052",stem:"Which electrolyte abnormality is most dangerous with digoxin therapy?",options:["Hypermagnesemia","Hypernatremia","Hypokalemia (low potassium increases digoxin binding and toxicity risk)","Hypocalcemia"],correctIndex:2,rationale:"Hypokalemia increases the risk of digoxin toxicity because potassium and digoxin compete for binding at the Na+/K+ ATPase. Low potassium = more digoxin binding = increased toxicity risk. Maintain K+ at 4-5 mEq/L.",difficulty:3,category:"Pharmacology",topic:"drug-electrolyte interactions"},
    {id:"pt-b9-053",stem:"The most common cause of drug-induced liver injury in the US is:",options:["Ibuprofen","Acetaminophen overdose","Aspirin","Amoxicillin"],correctIndex:1,rationale:"Acetaminophen is the most common cause of acute liver failure in the US, responsible for approximately 50% of cases. Toxicity occurs when the metabolite NAPQI overwhelms glutathione stores, causing hepatocellular necrosis.",difficulty:3,category:"Medication Safety",topic:"hepatotoxicity"},
    {id:"pt-b9-054",stem:"Pantoprazole IV is compatible with which diluent for administration?",options:["D10W","D50W","Sterile Water for Injection without further dilution","0.9% NaCl, D5W, or Lactated Ringer's"],correctIndex:3,rationale:"Pantoprazole IV can be diluted in 0.9% NaCl, D5W, or LR for infusion. It should be infused over 15 minutes. SWFI can be used for reconstitution but further dilution in a compatible IV fluid is required for administration.",difficulty:3,category:"Compounding",topic:"IV compatibility"},
    {id:"pt-b9-055",stem:"A 'tall man letter' version of chlorproMAZINE vs chlorproPAMIDE distinguishes:",options:["An antipsychotic (chlorpromazine) from an oral hypoglycemic (chlorpropamide)","Brand vs generic versions","Two dosage forms of the same drug","Two identical drugs"],correctIndex:0,rationale:"ChlorproMAZINE is a first-generation antipsychotic (phenothiazine). ChlorproPAMIDE is a sulfonylurea (oral hypoglycemic). Confusion could lead to serious hypoglycemia or uncontrolled psychiatric symptoms.",difficulty:3,category:"Medication Safety",topic:"tall man lettering"},
    {id:"pt-b9-056",stem:"Which compounding excipient is used as a humectant to prevent a topical preparation from drying out?",options:["Silicon dioxide","Glycerin","Talc","Starch"],correctIndex:1,rationale:"Glycerin (glycerol) is a humectant that attracts and retains moisture in topical preparations. Other humectants include propylene glycol and sorbitol. They prevent creams and ointments from drying out.",difficulty:3,category:"Compounding",topic:"excipients"},
    {id:"pt-b9-057",stem:"A sealed package of sterile supplies (e.g., syringes) should be checked for all of the following before use EXCEPT:",options:["Sterilization indicator","The retail price of the item","Expiration date","Package integrity (no tears or punctures)"],correctIndex:1,rationale:"Before using sterile supplies, check package integrity (tears, punctures, moisture), expiration date, and sterilization indicator (color change). Retail price is irrelevant to determining if the product is safe for use.",difficulty:3,category:"Compounding",topic:"supply verification"},
    {id:"pt-b9-058",stem:"An error occurred where a 10-fold overdose of insulin was given to a patient. This type of error is classified as:",options:["A wrong route error","A wrong drug error","A wrong patient error","A dosing error (wrong dose)"],correctIndex:3,rationale:"This is a dosing error—the correct drug was given to the correct patient by the correct route, but at the wrong (10× higher) dose. Common causes include decimal point errors, confusion between units and mL, or misread prescriptions.",difficulty:3,category:"Medication Safety",topic:"error classification"},
    {id:"pt-b9-059",stem:"The Vaccine Adverse Event Reporting System (VAERS) is co-managed by:",options:["The CDC and FDA","DEA and FBI","CMS and HRSA","OSHA and EPA"],correctIndex:0,rationale:"VAERS is a national passive surveillance system co-managed by the CDC and FDA to detect possible safety issues with US-licensed vaccines. Healthcare providers, manufacturers, and the public can submit reports.",difficulty:3,category:"Pharmacy Law",topic:"vaccine safety reporting"},
    {id:"pt-b9-060",stem:"When compounding a topical cream with hydrocortisone, the final product should be checked for:",options:["Only color","Only taste","Uniform consistency, absence of grittiness, proper labeling, and appropriate BUD","Only smell"],correctIndex:2,rationale:"Quality checks for compounded creams include visual inspection (uniform color and texture), feel (absence of grittiness indicating undissolved drug), proper labeling (drug name, strength, BUD, directions), and documentation.",difficulty:3,category:"Compounding",topic:"quality control"},
    {id:"pt-b9-061",stem:"Methadone has a unique pharmacokinetic property that makes dosing challenging:",options:["It cannot be given orally","It has no drug interactions","It is rapidly eliminated","Its analgesic duration (4-8 hours) is much shorter than its elimination half-life (8-59 hours), leading to accumulation with repeated dosing"],correctIndex:3,rationale:"Methadone's long, variable half-life causes accumulation over 3-5 days of dosing. Peak respiratory depression may occur later than peak analgesia. Dose titration must be slow and carefully monitored.",difficulty:3,category:"Pharmacology",topic:"opioid pharmacokinetics"},
    {id:"pt-b9-062",stem:"A patient asks: 'Can I take my statin with grapefruit juice?' For simvastatin the answer is:",options:["Yes, it improves absorption","Only with breakfast","Grapefruit juice has no effect","No—grapefruit juice inhibits CYP3A4, which can significantly increase simvastatin levels and risk of myopathy/rhabdomyolysis"],correctIndex:3,rationale:"Grapefruit juice inhibits intestinal CYP3A4 and P-glycoprotein, increasing simvastatin (and lovastatin) levels by 3-16 fold. This dramatically increases risk of myopathy. Rosuvastatin and pravastatin are safe alternatives.",difficulty:3,category:"Pharmacology",topic:"food-drug interactions"},
    {id:"pt-b9-063",stem:"What does the term 'polypharmacy' refer to?",options:["A pharmacy with multiple locations","The concurrent use of multiple medications (typically 5 or more), which increases risk of drug interactions and adverse effects","Using multiple dosage forms of the same drug","A prescription with multiple refills"],correctIndex:1,rationale:"Polypharmacy is common in elderly patients and increases risks of drug interactions, adverse effects, medication non-adherence, falls, and hospitalizations. Medication reconciliation and deprescribing help manage polypharmacy.",difficulty:3,category:"Medication Safety",topic:"polypharmacy"},
    {id:"pt-b9-064",stem:"Cyclosporine (Sandimmune vs Neoral/Gengraf) illustrates what important dispensing principle?",options:["Brand and generic are always interchangeable","Only the newest formulation should be used","All formulations of a drug are identical","Different formulations of the same drug are NOT interchangeable—Sandimmune and Neoral have different bioavailability profiles"],correctIndex:3,rationale:"Sandimmune (oil-based) and Neoral/Gengraf (microemulsion) have different absorption profiles and are NOT interchangeable. Switching formulations can cause rejection or toxicity in transplant patients. Drug monitoring is essential.",difficulty:3,category:"Medication Safety",topic:"formulation safety"},
    {id:"pt-b9-065",stem:"What is the purpose of a medication guide vs a patient package insert (PPI)?",options:["MedGuides are FDA-required for specific high-risk medications; PPIs provide detailed product information for specific drug classes (e.g., oral contraceptives, estrogen products)","MedGuides are for pharmacists only","They are identical documents","PPIs are advertising materials"],correctIndex:0,rationale:"MedGuides: FDA-mandated patient information for specific high-risk drugs (must be given at dispensing). PPIs: detailed product information required for specific products like oral contraceptives and estrogens.",difficulty:3,category:"Medication Order Processing",topic:"patient information"},
    {id:"pt-b9-066",stem:"A drug with 90% protein binding means:",options:["90% of the drug is bound to plasma proteins and only 10% is free (active) and available for pharmacological effect","The drug is 90% absorbed","The drug has 90% bioavailability","90% of the drug is excreted unchanged"],correctIndex:0,rationale:"Protein-bound drug is pharmacologically inactive (reservoir). Only the free (unbound) fraction distributes to tissues and produces effects. Drug interactions displacing protein-bound drugs can increase free drug levels and toxicity risk.",difficulty:3,category:"Pharmacology",topic:"pharmacokinetics"},
    {id:"pt-b9-067",stem:"A pharmacy implements barcode medication administration (BCMA). This technology primarily reduces which type of error?",options:["Compounding errors","Prescribing errors","Wrong-patient and wrong-drug errors at the point of administration","Insurance billing errors"],correctIndex:2,rationale:"BCMA verifies the right patient (wristband scan), right drug (medication barcode scan), right dose, and right time at the bedside before administration. Studies show 50-87% reduction in administration errors.",difficulty:3,category:"Medication Safety",topic:"technology safety"},
    {id:"pt-b9-068",stem:"Under HIPAA regulations, a pharmacy technician may share patient medication information with which of the following without patient authorization?",options:["The patients neighbor who is picking up the prescription","The patients treating physician requesting medication history","The patients employer","A pharmaceutical sales representative"],correctIndex:1,rationale:"HIPAA permits sharing protected health information for treatment purposes without explicit patient authorization. A treating physician requesting medication history falls under the treatment exception to the HIPAA Privacy Rule.",difficulty:3,category:"Pharmacy Law",topic:"HIPAA privacy"},
    {id:"pt-b9-069",stem:"The Anti-Kickback Statute makes it illegal to:",options:["Transfer prescriptions between pharmacies","Dispense generic medications","Offer patient counseling","Offer, pay, solicit, or receive anything of value in exchange for referrals or to induce the purchase of items covered by federal healthcare programs"],correctIndex:3,rationale:"The federal Anti-Kickback Statute (AKS) prohibits offering or receiving remuneration to induce referrals for services covered by federal programs (Medicare, Medicaid). Violations carry criminal penalties.",difficulty:3,category:"Pharmacy Law",topic:"healthcare fraud laws"},
    {id:"pt-b9-070",stem:"A compounded sterile preparation that contains multiple drugs must be checked for:",options:["Only the color of the solution","Physical and chemical compatibility between all ingredients","Only the container type","Only the volume"],correctIndex:1,rationale:"Multi-drug CSPs require compatibility verification (physical: precipitation, color change, cloudiness; chemical: degradation, loss of potency). Resources include Trissel's Handbook, King Guide, and manufacturer compatibility data.",difficulty:3,category:"Compounding",topic:"drug compatibility"},
    {id:"pt-b9-071",stem:"What is the role of surfactants in pharmaceutical compounding?",options:["To add color","To increase shelf life","To increase drug cost","To reduce surface tension between immiscible phases, helping to create stable emulsions and improve drug wetting"],correctIndex:3,rationale:"Surfactants (emulsifiers, wetting agents) reduce interfacial tension between oil and water phases. Common surfactants include polysorbate 80, sodium lauryl sulfate, and lecithin. They stabilize emulsions and improve drug dissolution.",difficulty:3,category:"Compounding",topic:"formulation science"},
    {id:"pt-b9-072",stem:"A medication that exhibits 'dose dumping' when crushed indicates:",options:["The entire sustained-release dose is released at once, potentially causing toxicity","The drug is inactive","Normal drug behavior","The drug must be taken with food"],correctIndex:0,rationale:"Dose dumping occurs when a modified-release formulation is damaged (crushed, chewed), releasing the entire dose immediately. For potent drugs (opioids, cardiovascular drugs), this can be life-threatening.",difficulty:3,category:"Medication Safety",topic:"do not crush"},
    {id:"pt-b9-073",stem:"The Drug Enforcement Administration (DEA) is part of which federal department?",options:["Department of Justice","Department of Defense","Department of Homeland Security","Department of Health and Human Services"],correctIndex:0,rationale:"The DEA is a component of the US Department of Justice. It enforces the Controlled Substances Act and regulates the manufacture, distribution, and dispensing of controlled substances.",difficulty:3,category:"Pharmacy Law",topic:"federal agencies"},
    {id:"pt-b9-074",stem:"Which calculation method is used to determine the number of calories from IV lipid emulsion (20%)?",options:["20% lipid emulsion provides 0.2 kcal/mL","20% lipid emulsion provides 10 kcal/mL","20% lipid emulsion provides 2 kcal/mL","20% lipid emulsion provides 20 kcal/mL"],correctIndex:2,rationale:"20% lipid emulsion (Intralipid 20%) provides 2 kcal/mL (from fat at 9 kcal/g plus glycerol and egg phospholipid calories). 10% lipid provides 1.1 kcal/mL.",difficulty:3,category:"Pharmacy Calculations",topic:"TPN calculations"},
    {id:"pt-b9-075",stem:"What is the significance of the USP <825> chapter?",options:["It covers hazardous drug handling","It covers non-sterile compounding","It establishes standards for radiopharmaceutical preparation, compounding, dispensing, and quality assurance","It covers sterile compounding"],correctIndex:2,rationale:"USP <825> provides standards specifically for radiopharmaceuticals, including preparation, compounding, dispensing, quality assurance, and radiation safety. Nuclear pharmacies must comply with both USP <825> and NRC regulations.",difficulty:3,category:"Compounding",topic:"radiopharmacy"},
    {id:"pt-b9-076",stem:"A look-back period in pharmacy refers to:",options:["The time period an insurance plan uses to determine if a refill is too early based on previous fill dates and day supply","The time it takes to process a claim","The shelf life of a medication","The time a pharmacist looks at a prescription"],correctIndex:0,rationale:"The look-back period is used by insurance plans to check previous claim history and determine if a refill request is too early. Typically, the claim will be rejected if less than 75-80% of the previous supply has been used.",difficulty:3,category:"Medication Order Processing",topic:"insurance processing"},
    {id:"pt-b9-077",stem:"Which laboratory test is used to monitor the therapeutic effectiveness of anticoagulant therapy with unfractionated heparin?",options:["INR/PT","Activated partial thromboplastin time (aPTT)","Hemoglobin A1C","Serum creatinine"],correctIndex:1,rationale:"aPTT monitors unfractionated heparin (UFH). Therapeutic range: 1.5-2.5 times the control value. Anti-Xa levels may also be used. INR/PT monitors warfarin. aPTT does not monitor LMWH (use anti-Xa).",difficulty:3,category:"Pharmacology",topic:"laboratory monitoring"},
    {id:"pt-b9-078",stem:"Calcium acetate (PhosLo) is used in patients with chronic kidney disease to:",options:["Lower blood pressure","Bind dietary phosphorus in the GI tract, preventing hyperphosphatemia","Treat osteoporosis","Prevent blood clots"],correctIndex:1,rationale:"In CKD, the kidneys cannot adequately excrete phosphorus. Calcium acetate binds phosphorus in the gut, forming insoluble calcium phosphate that is excreted in the stool. Must be taken with meals.",difficulty:3,category:"Pharmacology",topic:"renal medications"},
    {id:"pt-b9-079",stem:"When a 'coverage gap' (donut hole) occurs in Medicare Part D, the patient:",options:["Pays a larger share of drug costs until the catastrophic coverage threshold is reached","Receives all medications for free","Must switch pharmacies","No longer has insurance coverage"],correctIndex:0,rationale:"Medicare Part D coverage gap: after initial coverage limit is reached, the patient pays 25% of brand-name and generic drug costs until out-of-pocket spending reaches the catastrophic threshold.",difficulty:4,category:"Medication Order Processing",topic:"Medicare Part D"},
    {id:"pt-b9-080",stem:"Which antidote is used for beta-blocker overdose?",options:["Protamine sulfate","Flumazenil","Naloxone","Glucagon"],correctIndex:3,rationale:"Glucagon bypasses beta-adrenergic receptors and directly stimulates cardiac cells via the glucagon receptor, increasing heart rate and contractility. It is the first-line antidote for beta-blocker toxicity with hemodynamic compromise.",difficulty:4,category:"Medication Safety",topic:"antidotes"},
    {id:"pt-b9-081",stem:"A prescription for 'Levothyroxine 88 mcg, take 1 tablet daily' should include which auxiliary label?",options:["Take with food","Chew before swallowing","Take at bedtime with milk","Take on an empty stomach 30-60 minutes before breakfast; separate from calcium and iron by 4 hours"],correctIndex:3,rationale:"Levothyroxine should be taken on an empty stomach to maximize absorption. Food, calcium, iron, and antacids significantly reduce absorption. Consistent timing helps maintain stable thyroid levels.",difficulty:4,category:"Medication Safety",topic:"auxiliary labels"},
    {id:"pt-b9-082",stem:"What is the generic name for Trulicity?",options:["Semaglutide","Dulaglutide","Exenatide","Liraglutide"],correctIndex:1,rationale:"Trulicity is dulaglutide, a once-weekly GLP-1 receptor agonist for type 2 diabetes. Byetta/Bydureon is exenatide. Victoza is liraglutide. Ozempic is semaglutide.",difficulty:4,category:"Pharmacology",topic:"brand/generic names"},
    {id:"pt-b9-083",stem:"A compounded preparation requires 5 g of Drug A and 95 g of Cream Base. The final concentration is:",options:["50%","0.05%","0.5%","5% w/w"],correctIndex:3,rationale:"Concentration = (Drug / Total) × 100 = (5 g / 100 g) × 100 = 5% weight/weight.",difficulty:4,category:"Pharmacy Calculations",topic:"concentrations"},
    {id:"pt-b9-084",stem:"Which blood thinner is derived from animal sources and must be dosed in units?",options:["Unfractionated heparin (from porcine intestinal mucosa)","Clopidogrel","Warfarin","Apixaban"],correctIndex:0,rationale:"UFH is extracted from porcine intestinal mucosa (or bovine lung). It is dosed in units, not mg. Its activity varies between batches, requiring aPTT or anti-Xa monitoring for therapeutic dosing.",difficulty:4,category:"Pharmacology",topic:"anticoagulants"},
    {id:"pt-b9-085",stem:"The term 'bioavailability' refers to:",options:["The speed of drug elimination","The drug's mechanism of action","The drug's side effect profile","The fraction of an administered dose that reaches systemic circulation in unchanged form"],correctIndex:3,rationale:"Bioavailability (F) = fraction of unchanged drug reaching systemic circulation. IV = 100% by definition. Oral bioavailability is reduced by incomplete absorption and first-pass metabolism. F is used to convert between routes.",difficulty:4,category:"Pharmacology",topic:"pharmacokinetics"},
    {id:"pt-b9-086",stem:"Which vaccine is a live attenuated vaccine and should NOT be given to immunocompromised patients?",options:["Hepatitis B","Pneumococcal polysaccharide (PPSV23)","Influenza (inactivated/IIV)","MMR (measles, mumps, rubella)"],correctIndex:3,rationale:"MMR is a live attenuated vaccine. Other live vaccines include varicella, LAIV (FluMist), rotavirus, yellow fever, and oral typhoid. Live vaccines are contraindicated in immunocompromised patients due to risk of vaccine-strain infection.",difficulty:4,category:"Pharmacology",topic:"vaccines"},
    {id:"pt-b9-087",stem:"The 'black box' around a drug warning in the package insert signifies:",options:["A cosmetic defect in the packaging","The drug is available OTC","The drug has been recalled","The most serious type of warning required by the FDA, indicating potential for serious injury or death"],correctIndex:3,rationale:"Boxed (black box) warnings are the highest level of FDA warning. They highlight serious risks, including death. Examples: suicidality with antidepressants, cardiovascular events with COX-2 inhibitors, and tendon rupture with fluoroquinolones.",difficulty:4,category:"Medication Safety",topic:"FDA warnings"},
    {id:"pt-b9-088",stem:"Dolutegravir (Tivicay) is an antiretroviral medication classified as:",options:["NNRTI","Protease inhibitor","NRTI","Integrase strand transfer inhibitor (INSTI)"],correctIndex:3,rationale:"Dolutegravir is an INSTI that blocks HIV integrase, preventing viral DNA integration into the host genome. INSTIs are now the preferred backbone class for initial HIV treatment regimens.",difficulty:4,category:"Pharmacology",topic:"HIV medications"},
    {id:"pt-b9-089",stem:"A patient is taking phenytoin and requires the addition of valproic acid. What drug interaction concern exists?",options:["Valproic acid decreases phenytoin levels","No interaction exists","Valproic acid displaces phenytoin from protein binding and inhibits its metabolism, significantly increasing free phenytoin levels and toxicity risk","They are incompatible dosage forms"],correctIndex:2,rationale:"Valproic acid displaces phenytoin from plasma proteins and inhibits CYP2C9/2C19 metabolism. This dual mechanism significantly increases free (active) phenytoin levels, requiring dose reduction and careful monitoring.",difficulty:4,category:"Pharmacology",topic:"drug interactions"},
    {id:"pt-b9-090",stem:"Abiraterone (Zytiga) is used in the treatment of:",options:["Breast cancer","Lung cancer","Colon cancer","Metastatic castration-resistant prostate cancer"],correctIndex:3,rationale:"Abiraterone inhibits CYP17A1, blocking androgen biosynthesis. It is used with prednisone for metastatic castration-resistant prostate cancer. Must be taken on an empty stomach (food increases absorption variably).",difficulty:4,category:"Pharmacology",topic:"oncology"},
    {id:"pt-b9-091",stem:"What is the maximum number of Schedule II prescriptions that can be issued for a single patient at one visit?",options:["Only one","Up to three 30-day prescriptions with future fill dates per some state laws (federal law does not specify a maximum number)","Ten","Unlimited"],correctIndex:1,rationale:"Some states allow prescribers to issue multiple Schedule II prescriptions at one visit with specific instructions for sequential filling (e.g., 'do not fill before' date). Federal law permits this; state laws vary.",difficulty:4,category:"Pharmacy Law",topic:"multiple CII prescriptions"},
    {id:"pt-b9-092",stem:"A drug labeled 'caution: federal law prohibits the transfer of this drug to any person other than the patient for whom it was prescribed' applies to:",options:["All prescription drugs dispensed in the US","Only controlled substances","Only compounded medications","Only OTC products"],correctIndex:0,rationale:"This federal transfer warning is required on the label of all prescription drugs. It reminds patients that sharing prescription medications with others is illegal and potentially dangerous.",difficulty:4,category:"Pharmacy Law",topic:"labeling requirements"},
    {id:"pt-b9-093",stem:"A capsule shell made of gelatin may not be suitable for which patient population?",options:["Vegetarian/vegan patients or those with religious dietary restrictions (e.g., halal, kosher) — HPMC (hypromellose) capsules are alternatives","Patients with hypertension","Elderly patients","Pediatric patients"],correctIndex:0,rationale:"Gelatin capsules are derived from animal sources (porcine or bovine). Vegetarian/vegan patients and those with religious restrictions may prefer HPMC (hydroxypropyl methylcellulose) capsules, which are plant-derived.",difficulty:4,category:"Compounding",topic:"capsule formulation"},
    {id:"pt-b9-094",stem:"How should a pharmacy handle an expired EpiPen returned by a patient?",options:["Return it to the manufacturer for full credit","Extend the expiration date","Redispense it to another patient","Accept it, document it, and dispose of it through proper pharmaceutical waste channels—do not redispense"],correctIndex:3,rationale:"Expired EpiPens should be accepted for disposal (medication take-back). They cannot be redispensed. Proper disposal prevents environmental contamination and accidental use of expired medication with potentially reduced potency.",difficulty:4,category:"Inventory Management",topic:"medication disposal"},
    {id:"pt-b9-095",stem:"The medication 'Xarelto 2.5 mg BID' is used for a different indication than 'Xarelto 20 mg daily.' The 2.5 mg BID dose is for:",options:["Post-surgical DVT prophylaxis","Atrial fibrillation stroke prevention","DVT/PE treatment","Reduction of risk of major cardiovascular events (with aspirin) in patients with chronic CAD or PAD"],correctIndex:3,rationale:"Rivaroxaban 2.5 mg BID (with aspirin) is the 'vascular dose' for reducing cardiovascular events in CAD/PAD. Higher doses (15-20 mg) treat DVT/PE and prevent stroke in atrial fibrillation. Different dose = different indication.",difficulty:4,category:"Pharmacology",topic:"indication-specific dosing"},
    {id:"pt-b9-096",stem:"A pharmacy's SOP (Standard Operating Procedure) manual is important because:",options:["It only covers financial procedures","It documents standardized processes to ensure consistency, quality, regulatory compliance, and training of new staff","It is optional and rarely used","It is only needed during inspections"],correctIndex:1,rationale:"SOPs document step-by-step procedures for all pharmacy operations (dispensing, compounding, inventory, safety). They ensure consistency, meet regulatory requirements, support training, and provide reference for quality audits.",difficulty:4,category:"Medication Order Processing",topic:"pharmacy operations"},
    {id:"pt-b9-097",stem:"Dexamethasone is approximately how many times more potent than prednisone as an anti-inflammatory?",options:["25 times more potent","Equal potency","5-7 times more potent (mg for mg)","Half as potent"],correctIndex:2,rationale:"Dexamethasone is approximately 5-7 times more potent than prednisone. Equivalencies: 0.75 mg dexamethasone ≈ 5 mg prednisone ≈ 20 mg hydrocortisone. Dexamethasone also has a longer duration of action.",difficulty:4,category:"Pharmacy Calculations",topic:"steroid equivalencies"},
    {id:"pt-b9-098",stem:"The SUPPORT Act (2018) affected controlled substance dispensing by:",options:["Requiring electronic prescribing of controlled substances under Medicare Part D and expanding partial fill options for Schedule II drugs","Eliminating all controlled substance regulations","Allowing OTC sale of opioids","Removing DEA requirements"],correctIndex:0,rationale:"The Substance Use-Disorder Prevention that Promotes Opioid Recovery and Treatment (SUPPORT) Act mandated EPCS for Medicare Part D, allowed partial fills of CII prescriptions at patient request, and strengthened PDMP requirements.",difficulty:4,category:"Pharmacy Law",topic:"opioid legislation"},
    {id:"pt-b9-099",stem:"When a patient reports a new allergy to sulfa drugs, which medications should be flagged in their profile?",options:["Only aspirin products","Sulfamethoxazole/trimethoprim (Bactrim), sulfasalazine, and potentially cross-reactive drugs like thiazide diuretics and sulfonylureas","Only cephalosporins","Only penicillins"],correctIndex:1,rationale:"Sulfa allergy primarily applies to sulfonamide antibiotics. Cross-reactivity with non-antibiotic sulfonamides (thiazides, furosemide, sulfonylureas, celecoxib) is debated but should be noted in the profile for pharmacist evaluation.",difficulty:5,category:"Medication Safety",topic:"allergy documentation"},
    {id:"pt-b9-100",stem:"The USP <800> requirement for assessment of risk began in which area of hazardous drug handling?",options:["All areas: receipt, storage, compounding, dispensing, administration, and deactivation/cleaning/disposal","Only compounding","Only disposal","Only administration"],correctIndex:0,rationale:"USP <800> requires a comprehensive assessment of risk throughout the entire hazardous drug handling continuum: receiving, storage, compounding, dispensing, administration, and deactivation/cleaning/disposal of hazardous drug waste.",difficulty:5,category:"Compounding",topic:"hazardous drug management"}
  ];
  